#include <stdio.h>
#include <stdlib.h>

int max(int a, int b)
{
    return a>b ? a : b;
}

int a[100], count;

int main()
{
    int n;
    scanf("%d", &n);

    int i, j, temp;

    for (i=0; i<n; i++)
    {
        scanf("%d", &a[i]);
        count += a[i];
    }

    ///printf("count : %d\n", count);

    temp = a[0];

    if (n>1)
    {
        for (i=0; i<n; i++)
        {
            temp = max(temp, a[i]);
        }
    }

    ///printf("temp : %d\n", temp);

    int k;

    int ans;

    for (i=0; ; i++)
    {
        k = temp+i;
        if (((n*k)-count)>count)
        {
            ans = k;
            break;
        }
    }

    printf("%d", ans);

    return 0;
}

